async function SpireLoadRemoteFile(fileName, vfsPath="/", fetchPath="") {
    let c = new Request(fetchPath + fileName);
    c = await (await (await fetch(c)).blob()).arrayBuffer();
    vfsFile = vfsPath + fileName;
    FS.analyzePath(vfsPath).exists || FS.mkdirTree(vfsPath);
    SpirePrepareFile(c, vfsFile);
    return vfsFile;
}
async function SpireLoadSettings() {
    let b = await fetch(".//settings.json");
    b.ok || (b = await fetch(".//settings.json.default"));
    if (b.ok) {
        const a = await b.json();
        await SpireLoadRemoteFile(a.license, "/lic/");
        for (const c of a.fontsList)
            await SpireLoadRemoteFile(c, "/Library/Fonts/", a.fontsDir);
        for (const c of a.files)
            await SpireLoadRemoteFile(c.fileName, c.fileTo, c.fileFrom);
    }
    return b.ok;
}
